/**
 * @file auth.ts
 * @description Authentication service with dynamic siwe import.
 * @layer Services
 *
 * Addresses audit finding C1: siwe is now dynamically imported only when
 * verifySiwe() is called, so the SDK loads without siwe installed.
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type {
  AuthCredentials,
  NonceResponse,
  SessionData,
  AuthResult,
  WalletAddress,
} from '@dial-wtf/core';
import { AuthError, ValidationError } from '@dial-wtf/core';

/** Authentication service for SIWE/SIWS */
export class AuthService extends BaseService {
  constructor(http: HttpClient) {
    super(http);
  }

  async getNonce(address: WalletAddress): Promise<string> {
    const response = await this.http.get<NonceResponse>(
      this.rawEndpoint('/siwe/nonce'),
      { address }
    );
    return response.nonce;
  }

  /**
   * Verify SIWE credentials and create session.
   *
   * Uses dynamic import() for siwe to avoid crashing if not installed (C1 fix).
   */
  async verifySiwe(message: string, signature: string): Promise<AuthResult> {
    let parsed: { address: string; chainId: number; nonce: string };

    try {
      const { SiweMessage } = await import('siwe');
      const siweMsg = new SiweMessage(message);
      parsed = {
        address: siweMsg.address,
        chainId: siweMsg.chainId,
        nonce: siweMsg.nonce,
      };
    } catch {
      // If siwe is not installed, parse fields from the raw message string
      parsed = this.parseSiweFields(message);
    }

    const response = await this.http.post<AuthResult>(
      this.rawEndpoint('/siwe/verify'),
      {
        message,
        signature,
        address: parsed.address,
        chainId: parsed.chainId,
        nonce: parsed.nonce,
      }
    );
    return response;
  }

  async verifySiws(message: string, signature: string): Promise<AuthResult> {
    const response = await this.http.post<AuthResult>(
      this.rawEndpoint('/siws/verify'),
      { message, signature }
    );
    return response;
  }

  async authenticate(credentials: AuthCredentials): Promise<AuthResult> {
    if (credentials.siwe) {
      return this.verifySiwe(
        credentials.siwe.message,
        credentials.siwe.signature
      );
    }

    if (credentials.siws) {
      return this.verifySiws(
        credentials.siws.message,
        credentials.siws.signature
      );
    }

    throw new ValidationError(
      'Either siwe or siws credentials must be provided'
    );
  }

  async validateSession(session: SessionData): Promise<boolean> {
    try {
      const expiresAt = new Date(session.expiresAt);
      if (expiresAt <= new Date()) {
        return false;
      }

      this.http.setAuthToken(session.token);
      const response = await this.http.get<{ valid: boolean }>(
        this.rawEndpoint('/auth/validate')
      );
      return response.valid;
    } catch {
      return false;
    }
  }

  async refreshSession(session: SessionData): Promise<SessionData> {
    if (!session.refreshToken) {
      throw new AuthError('No refresh token available');
    }

    const response = await this.http.post<SessionData>(
      this.rawEndpoint('/auth/refresh'),
      { refreshToken: session.refreshToken }
    );

    return response;
  }

  async logout(): Promise<void> {
    await this.http.post(this.rawEndpoint('/auth/logout'));
  }

  getWalletAddress(session: SessionData): WalletAddress {
    return session.walletAddress;
  }

  /**
   * Fallback SIWE message parser when the siwe package is not installed.
   * Extracts address, chainId, and nonce from the EIP-4361 formatted string.
   */
  private parseSiweFields(message: string): { address: string; chainId: number; nonce: string } {
    const lines = message.split('\n');
    let address = '';
    let chainId = 1;
    let nonce = '';

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i]!.trim();
      // Address is the line after "wants you to sign in with your Ethereum account:"
      if (i === 1 && /^0x[a-fA-F0-9]{40}$/.test(line)) {
        address = line;
      }
      if (line.startsWith('Chain ID:')) {
        chainId = parseInt(line.replace('Chain ID:', '').trim(), 10);
      }
      if (line.startsWith('Nonce:')) {
        nonce = line.replace('Nonce:', '').trim();
      }
    }

    return { address, chainId, nonce };
  }
}
