/**
 * @file registry.ts
 * @description Registry service - public features (no auth required).
 * @layer Services
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type { ConferenceRoom, DialProfile, PaginationParams, WalletAddress } from '@dial-wtf/core';

export interface ProfileSearchResult {
  walletAddress: string;
  displayName: string;
  avatar?: string;
  bio?: string;
}

export class RegistryService extends BaseService {
  constructor(http: HttpClient) { super(http); }

  async listPublicRooms(params?: PaginationParams): Promise<ConferenceRoom[]> {
    return this.http.get<ConferenceRoom[]>(this.endpoint('/registry/rooms'), params ? { limit: params.limit, offset: params.offset } : undefined);
  }

  async getTokenInfo(contractAddress: string): Promise<{ name: string; symbol: string; decimals: number; totalSupply: string }> {
    return this.http.get(this.endpoint(`/registry/tokens/${contractAddress}`));
  }

  async searchProfiles(options: { query: string; limit?: number }): Promise<ProfileSearchResult[]> {
    return this.http.get<ProfileSearchResult[]>(this.endpoint('/registry/profiles/search'), options);
  }

  async getProfileByENS(ensName: string): Promise<DialProfile> {
    return this.http.get<DialProfile>(this.endpoint(`/registry/ens/${ensName}`));
  }

  /**
   * Batch lookup profiles by wallet addresses.
   * Fetches up to 100 profiles in a single HTTP request.
   *
   * @example
   * ```typescript
   * const profiles = await dial.registry.getProfiles({
   *   addresses: ['0xabc...', '0xdef...']
   * });
   * ```
   */
  async getProfiles(options: { addresses: WalletAddress[] }): Promise<Map<WalletAddress, DialProfile>> {
    const profiles = await this.http.post<DialProfile[]>(
      this.endpoint('/registry/profiles/batch'),
      { addresses: options.addresses },
    );
    const map = new Map<WalletAddress, DialProfile>();
    for (const p of profiles) {
      map.set(p.walletAddress, p);
    }
    return map;
  }

  /**
   * Resolve the verified on-chain primary ENS name for an address.
   * Returns null if no reverse ENS record is set.
   *
   * @example
   * ```typescript
   * const ens = await dial.registry.resolveENS('0x123...');
   * // => { ensName: 'vitalik.eth', verified: true }
   * ```
   */
  async resolveENS(address: WalletAddress): Promise<{ ensName: string; verified: boolean } | null> {
    try {
      return await this.http.get<{ ensName: string; verified: boolean }>(
        this.endpoint(`/registry/ens/resolve/${address}`),
      );
    } catch {
      return null;
    }
  }
}
