/**
 * @file contacts-book-api.ts
 * @description ApiContactsBookProvider — backend-backed contacts storage.
 * @layer Services
 *
 * Provider that delegates CRUD operations to the PeerSpeak /profile/contacts
 * API routes. Accepts either an HttpClient instance or a config object
 * so consumers can construct it without internal SDK plumbing (P2-3 fix).
 */

import { HttpClient } from '../http/client';
import { getFetch } from '@dial-wtf/core';
import type { ResolvedClientConfig } from '@dial-wtf/core';
import type { IContactsBookProvider, Contact, AddContactOptions, UpdateContactOptions, WalletAddress, PaginationParams } from '@dial-wtf/core';

/** Config for constructing an ApiContactsBookProvider without an HttpClient. */
export interface ApiContactsBookProviderConfig {
  /** API key for authentication. */
  apiKey?: string;
  /** Base URL of the Dial API (e.g., 'https://api.dial.wtf/v1'). */
  baseUrl: string;
  /** Bearer token for the authenticated session. */
  token: string;
  /** API version prefix (default: 'v1'). */
  apiVersion?: string;
}

export class ApiContactsBookProvider implements IContactsBookProvider {
  private readonly http: HttpClient;
  private readonly apiVersion: string;

  /**
   * Create with an existing HttpClient instance (internal SDK usage).
   */
  constructor(http: HttpClient, apiVersion?: string);
  /**
   * Create with a config object (external consumer usage).
   * No need to import or construct HttpClient yourself.
   */
  constructor(config: ApiContactsBookProviderConfig);
  constructor(
    httpOrConfig: HttpClient | ApiContactsBookProviderConfig,
    apiVersion?: string,
  ) {
    if (httpOrConfig instanceof HttpClient) {
      this.http = httpOrConfig;
      this.apiVersion = apiVersion ?? 'v1';
    } else {
      const config: ResolvedClientConfig = {
        baseUrl: httpOrConfig.baseUrl,
        apiKey: httpOrConfig.apiKey,
        timeout: 30000,
        debug: false,
        fetch: getFetch(),
      };
      this.http = new HttpClient(config);
      this.http.setAuthToken(httpOrConfig.token);
      this.apiVersion = httpOrConfig.apiVersion ?? 'v1';
    }
  }

  async getAll(params?: PaginationParams): Promise<Contact[]> {
    return this.http.get<Contact[]>(this.endpoint('/profile/contacts'), params ? { ...params } : undefined);
  }

  async get(walletAddress: WalletAddress): Promise<Contact | null> {
    try {
      const contacts = await this.getAll();
      return contacts.find(c => c.walletAddress.toLowerCase() === walletAddress.toLowerCase()) ?? null;
    } catch {
      return null;
    }
  }

  async add(options: AddContactOptions): Promise<Contact> {
    return this.http.post<Contact>(this.endpoint('/profile/contacts'), options);
  }

  async update(options: UpdateContactOptions): Promise<Contact> {
    return this.http.patch<Contact>(this.endpoint(`/profile/contacts/${options.walletAddress}`), options);
  }

  async remove(walletAddress: WalletAddress): Promise<void> {
    await this.http.delete(this.endpoint(`/profile/contacts/${walletAddress}`));
  }

  async has(walletAddress: WalletAddress): Promise<boolean> {
    const contact = await this.get(walletAddress);
    return contact !== null;
  }

  private endpoint(path: string): string {
    return `/${this.apiVersion}${path}`;
  }
}
