/**
 * @file conference.ts
 * @description Conference service for multi-party video conferencing rooms.
 * @layer Services
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type {
  ConferenceRoom,
  CreateRoomOptions,
  JoinRoomOptions,
  JoinByUrlOptions,
  Participant,
  RoomRecording,
  RoomMessage,
  SendRoomMessageOptions,
  BreakoutRoom,
  CreateBreakoutRoomsOptions,
  Poll,
  CreatePollOptions,
  PollResults,
  VideoQualitySettings,
  LayoutOption,
  SetLayoutOptions,
  RoomStats,
  IMediaProvider,
  MediaProviderConfig,
} from '@dial-wtf/core';

export class ConferenceService extends BaseService {
  private participantStreams: Map<string, MediaStream> = new Map();
  private _mediaProvider: IMediaProvider | null = null;

  constructor(http: HttpClient) { super(http); }

  setMediaProvider(provider: IMediaProvider | null): void { this._mediaProvider = provider; }
  get mediaProvider(): IMediaProvider | null { return this._mediaProvider; }

  async connectMedia(room: ConferenceRoom, userName: string, config?: MediaProviderConfig): Promise<void> {
    if (!this._mediaProvider) throw new Error('No media provider set. Call setMediaProvider() first.');
    if (!room.mediaToken) throw new Error('Room has no mediaToken. Backend may not have HMS integration enabled.');
    await this._mediaProvider.connect({ authToken: room.mediaToken, userName, roomId: room.hmsRoomId }, config);
  }

  async disconnectMedia(): Promise<void> {
    if (!this._mediaProvider) return;
    try { await this._mediaProvider.disconnect(); } catch (err) { console.warn('[Dial SDK] Media disconnect error (non-fatal):', err); }
  }

  async create(options: CreateRoomOptions): Promise<ConferenceRoom> { return this.http.post<ConferenceRoom>(this.endpoint('/conference/rooms'), options); }

  async join(options: JoinRoomOptions): Promise<ConferenceRoom> {
    const response = await this.http.post<ConferenceRoom & { token?: string; role?: string }>(this.endpoint(`/conference/rooms/${options.roomId}/join`), { video: options.video, audio: options.audio, displayName: options.displayName });
    return this.normalizeRoomResponse(response);
  }

  async joinByUrl(options: JoinByUrlOptions): Promise<ConferenceRoom> {
    const response = await this.http.post<ConferenceRoom & { token?: string; role?: string }>(this.endpoint('/conference/rooms/join-by-url'), options);
    return this.normalizeRoomResponse(response);
  }

  private normalizeRoomResponse(response: ConferenceRoom & { token?: string; role?: string }): ConferenceRoom {
    const { token, role, ...rest } = response;
    return { ...rest, mediaToken: rest.mediaToken ?? token, mediaRole: rest.mediaRole ?? role };
  }

  async leave(roomId: string): Promise<void> {
    await this.http.post(this.endpoint(`/conference/rooms/${roomId}/leave`));
    this.participantStreams.delete(roomId);
    await this.disconnectMedia();
  }

  async getParticipants(roomId: string): Promise<Participant[]> { return this.http.get<Participant[]>(this.endpoint(`/conference/rooms/${roomId}/participants`)); }
  getParticipantStream(roomId: string, participantId: string): MediaStream | undefined { return this.participantStreams.get(`${roomId}:${participantId}`); }

  async muteAudio(roomId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/mute-audio`)); this._mediaDispatch(() => this._mediaProvider!.setLocalAudioEnabled(false)); }
  async unmuteAudio(roomId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/unmute-audio`)); this._mediaDispatch(() => this._mediaProvider!.setLocalAudioEnabled(true)); }
  async muteParticipant(roomId: string, participantId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/participants/${participantId}/mute`)); }
  async muteAll(roomId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/mute-all`)); }
  async disableVideo(roomId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/disable-video`)); this._mediaDispatch(() => this._mediaProvider!.setLocalVideoEnabled(false)); }
  async enableVideo(roomId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/enable-video`)); this._mediaDispatch(() => this._mediaProvider!.setLocalVideoEnabled(true)); }
  async requestVideo(roomId: string, participantId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/participants/${participantId}/request-video`)); }
  async startScreenShare(roomId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/screen-share/start`)); this._mediaDispatch(() => this._mediaProvider!.startScreenShare()); }
  async stopScreenShare(roomId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/screen-share/stop`)); this._mediaDispatch(() => this._mediaProvider!.stopScreenShare()); }
  async startRecording(roomId: string): Promise<RoomRecording> { return this.http.post<RoomRecording>(this.endpoint(`/conference/rooms/${roomId}/recording/start`)); }
  async stopRecording(roomId: string): Promise<RoomRecording> { return this.http.post<RoomRecording>(this.endpoint(`/conference/rooms/${roomId}/recording/stop`)); }
  async getRecordings(roomId: string): Promise<RoomRecording[]> { return this.http.get<RoomRecording[]>(this.endpoint(`/conference/rooms/${roomId}/recordings`)); }
  async sendMessage(roomId: string, options: SendRoomMessageOptions): Promise<RoomMessage> { return this.http.post<RoomMessage>(this.endpoint(`/conference/rooms/${roomId}/messages`), options); }
  async setLayout(roomId: string, layout: LayoutOption, options?: SetLayoutOptions): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/layout`), { layout, ...options }); }
  async end(roomId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/end`)); }
  async removeParticipant(roomId: string, participantId: string): Promise<void> { await this.http.delete(this.endpoint(`/conference/rooms/${roomId}/participants/${participantId}`)); }
  async transferHost(roomId: string, newHostParticipantId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/transfer-host`), { participantId: newHostParticipantId }); }
  async createBreakoutRooms(roomId: string, options: CreateBreakoutRoomsOptions): Promise<BreakoutRoom[]> { return this.http.post<BreakoutRoom[]>(this.endpoint(`/conference/rooms/${roomId}/breakout-rooms`), options); }
  async moveToBreakout(roomId: string, participantId: string, breakoutRoomId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/breakout-rooms/${breakoutRoomId}/move`), { participantId }); }
  async closeBreakoutRooms(roomId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/breakout-rooms/close`)); }
  async createPoll(roomId: string, options: CreatePollOptions): Promise<Poll> { return this.http.post<Poll>(this.endpoint(`/conference/rooms/${roomId}/polls`), options); }
  async vote(roomId: string, pollId: string, optionIndex: number): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/polls/${pollId}/vote`), { optionIndex }); }
  async getPollResults(roomId: string, pollId: string): Promise<PollResults> { return this.http.get<PollResults>(this.endpoint(`/conference/rooms/${roomId}/polls/${pollId}/results`)); }
  async raiseHand(roomId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/raise-hand`)); }
  async lowerHand(roomId: string): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/lower-hand`)); }
  async setVideoQuality(roomId: string, settings: VideoQualitySettings): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/quality`), settings); }
  async setAdaptiveQuality(roomId: string, enabled: boolean): Promise<void> { await this.http.post(this.endpoint(`/conference/rooms/${roomId}/adaptive-quality`), { enabled }); }
  async getStats(roomId: string): Promise<RoomStats> { return this.http.get<RoomStats>(this.endpoint(`/conference/rooms/${roomId}/stats`)); }

  /** @internal */
  _setParticipantStream(roomId: string, participantId: string, stream: MediaStream): void { this.participantStreams.set(`${roomId}:${participantId}`, stream); }

  private _mediaDispatch(fn: () => Promise<void>): void {
    if (!this._mediaProvider) return;
    fn().catch((err) => { console.warn('[Dial SDK] Media provider error (non-fatal):', err); });
  }
}
