/**
 * @file contacts-book-local.ts
 * @description LocalContactsBookProvider — IDialStorage-backed contacts storage.
 * @layer Services
 *
 * Default provider that persists contacts per-wallet via IDialStorage (platform-agnostic).
 * Uses BrowserStorage by default in browsers, MemoryStorage as fallback.
 * Works offline with zero backend dependencies.
 *
 * Addresses audit finding C3: no direct localStorage usage — works in
 * Chrome Extension MV3 service workers when given a chrome.storage adapter.
 */

import type { IContactsBookProvider, Contact, AddContactOptions, UpdateContactOptions, WalletAddress, IDialStorage } from '@dial-wtf/core';
import { NotFoundError, MemoryStorage, BrowserStorage, IS_BROWSER } from '@dial-wtf/core';

export interface LocalContactsBookProviderOptions {
  /** Owner wallet address — used to namespace storage keys */
  walletAddress: WalletAddress;
  /** Storage key prefix (default: 'dial_contacts') */
  storagePrefix?: string;
  /** Custom storage backend (default: BrowserStorage in browsers, MemoryStorage elsewhere) */
  storage?: IDialStorage;
}

export class LocalContactsBookProvider implements IContactsBookProvider {
  private readonly storageKey: string;
  private readonly storage: IDialStorage;
  private cache: Map<string, Contact> = new Map();
  private loaded = false;

  constructor(options: LocalContactsBookProviderOptions) {
    const prefix = options.storagePrefix ?? 'dial_contacts';
    this.storageKey = `${prefix}:${options.walletAddress.toLowerCase()}`;
    this.storage = options.storage ?? (IS_BROWSER ? new BrowserStorage() : new MemoryStorage());
  }

  async getAll(): Promise<Contact[]> {
    await this.ensureLoaded();
    return Array.from(this.cache.values());
  }

  async get(walletAddress: WalletAddress): Promise<Contact | null> {
    await this.ensureLoaded();
    return this.cache.get(walletAddress.toLowerCase()) ?? null;
  }

  async add(options: AddContactOptions): Promise<Contact> {
    await this.ensureLoaded();
    const key = options.walletAddress.toLowerCase();

    const contact: Contact = {
      walletAddress: options.walletAddress,
      profile: {
        walletAddress: options.walletAddress,
        displayName: options.nickname ?? options.walletAddress,
        status: 'offline',
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      },
      nickname: options.nickname,
      tags: options.tags,
      addedAt: new Date().toISOString(),
    };

    this.cache.set(key, contact);
    await this.persist();
    return contact;
  }

  async update(options: UpdateContactOptions): Promise<Contact> {
    await this.ensureLoaded();
    const key = options.walletAddress.toLowerCase();
    const existing = this.cache.get(key);

    if (!existing) {
      throw new NotFoundError(`Contact ${options.walletAddress} not found`);
    }

    const updated: Contact = {
      ...existing,
      nickname: options.nickname ?? existing.nickname,
      tags: options.tags ?? existing.tags,
      notes: options.notes ?? existing.notes,
    };

    this.cache.set(key, updated);
    await this.persist();
    return updated;
  }

  async remove(walletAddress: WalletAddress): Promise<void> {
    await this.ensureLoaded();
    this.cache.delete(walletAddress.toLowerCase());
    await this.persist();
  }

  async has(walletAddress: WalletAddress): Promise<boolean> {
    await this.ensureLoaded();
    return this.cache.has(walletAddress.toLowerCase());
  }

  private async ensureLoaded(): Promise<void> {
    if (this.loaded) return;
    this.loaded = true;

    try {
      const raw = await this.storage.getItem(this.storageKey);
      if (raw) {
        const contacts: Contact[] = JSON.parse(raw);
        for (const c of contacts) {
          this.cache.set(c.walletAddress.toLowerCase(), c);
        }
      }
    } catch {
      this.cache.clear();
    }
  }

  private async persist(): Promise<void> {
    try {
      const contacts = Array.from(this.cache.values());
      await this.storage.setItem(this.storageKey, JSON.stringify(contacts));
    } catch {
      // Storage full or unavailable — fail silently
    }
  }
}
