/**
 * DialClient - Main SDK Entry Point
 *
 * The DialClient is the primary entry point for the Dial SDK. It provides
 * both unauthenticated (universal) and authenticated (user-bound) access
 * to Dial features.
 *
 * @remarks
 * This client is fully isomorphic and works in both browser and Node.js environments.
 * Some features (like media streaming) require browser-specific APIs.
 *
 * @example
 * ```typescript
 * import { DialClient } from '@dial-wtf/client';
 *
 * // Initialize universal client
 * const dial = new DialClient({
 *   apiKey: process.env.DIAL_API_KEY,
 *   network: 'mainnet' // or 'staging', 'testnet'
 * });
 *
 * // Use public features (no auth required)
 * const rooms = await dial.partyLines.getActive();
 *
 * // Authenticate for user-specific features
 * const userDialer = await dial.asUser({
 *   siwe: { message, signature }
 * });
 * ```
 *
 * @module @dial-wtf/client
 */

import type {
  DialClientConfig,
  ResolvedClientConfig,
  AuthCredentials,
  SessionData,
} from '@dial-wtf/core';
import { SDK_VERSION, API_BASE_URLS, DEFAULT_NETWORK } from '@dial-wtf/core';
import { ValidationError } from '@dial-wtf/core';
import { getFetch, detectEnvironment } from '@dial-wtf/core';
import { HttpClient } from '../http/client';
import { AuthService } from '../services/auth';
import { PartyLinesService } from '../services/party-lines';
import { RegistryService } from '../services/registry';
import { UserDialer } from './user-dialer';

/**
 * Main Dial SDK client
 *
 * Provides access to both public (unauthenticated) and authenticated features.
 */
export class DialClient {
  /** SDK version */
  static readonly version = SDK_VERSION;

  private readonly config: ResolvedClientConfig;
  private readonly http: HttpClient;

  /**
   * Authentication service
   *
   * @remarks
   * Isomorphic - works in both browser and Node.js
   *
   * @example
   * ```typescript
   * // Get nonce for SIWE message
   * const nonce = await dial.auth.getNonce();
   * ```
   */
  public readonly auth: AuthService;

  /**
   * Party Lines service - query and create party lines
   *
   * @remarks
   * Isomorphic - works in both browser and Node.js
   * Read operations don't require authentication.
   * Write operations require an API key.
   *
   * @example
   * ```typescript
   * // Get active party lines (no auth required)
   * const partyLines = await dial.partyLines.getActive();
   *
   * // Create party line (requires API key)
   * const room = await dial.partyLines.create({
   *   owner: '0x...',
   *   name: 'My Room'
   * });
   * ```
   */
  public readonly partyLines: PartyLinesService;

  /**
   * Registry service - public registry features
   *
   * @remarks
   * Isomorphic - works in both browser and Node.js
   * No authentication required.
   *
   * @example
   * ```typescript
   * // Search profiles
   * const profiles = await dial.registry.searchProfiles({ query: 'alice' });
   *
   * // Get profile by ENS
   * const profile = await dial.registry.getProfileByENS('alice.eth');
   * ```
   */
  public readonly registry: RegistryService;

  /**
   * Create a new DialClient instance
   *
   * @param config - Client configuration options
   */
  constructor(config: DialClientConfig = {}) {
    this.config = this.resolveConfig(config);
    this.http = new HttpClient(this.config);

    // Initialize public services
    this.auth = new AuthService(this.http);
    this.partyLines = new PartyLinesService(this.http);
    this.registry = new RegistryService(this.http);
  }

  /**
   * Resolve configuration with defaults
   */
  private resolveConfig(config: DialClientConfig): ResolvedClientConfig {
    const network = config.network ?? DEFAULT_NETWORK;
    const baseUrl = config.baseUrl ?? API_BASE_URLS[network];

    return {
      apiKey: config.apiKey,
      baseUrl,
      timeout: config.timeout ?? 30000,
      debug: config.debug ?? false,
      fetch: config.fetch ?? getFetch(),
    };
  }

  /**
   * Authenticate and create a user-bound client
   *
   * @remarks
   * Pass either SIWE (Ethereum) or SIWS (Solana) credentials.
   * Returns a UserDialer instance with access to all authenticated features.
   *
   * @example
   * ```typescript
   * // With SIWE (Ethereum)
   * const userDialer = await dial.asUser({
   *   siwe: { message, signature }
   * });
   *
   * // With SIWS (Solana)
   * const userDialer = await dial.asUser({
   *   siws: { message, signature }
   * });
   * ```
   */
  async asUser(credentials: AuthCredentials): Promise<UserDialer> {
    if (!credentials.siwe && !credentials.siws) {
      throw new ValidationError(
        "Either siwe or siws credentials must be provided"
      );
    }

    const authResult = await this.auth.authenticate(credentials);
    return new UserDialer(this.http, authResult.session, undefined, undefined, this.auth);
  }

  /**
   * Restore a session from exported session data
   *
   * @remarks
   * Use this to restore a previously authenticated session without
   * requiring the user to sign again.
   *
   * @example
   * ```typescript
   * // Restore from localStorage
   * const sessionData = JSON.parse(localStorage.getItem('dial_session'));
   * const userDialer = await dial.restoreSession(sessionData);
   *
   * // Validate session is still active
   * if (await userDialer.isSessionValid()) {
   *   console.log('Session restored successfully');
   * }
   * ```
   */
  async restoreSession(session: SessionData): Promise<UserDialer> {
    // Validate session structure
    if (!session.walletAddress || !session.token || !session.expiresAt) {
      throw new ValidationError("Invalid session data");
    }

    // Check if expired locally
    const expiresAt = new Date(session.expiresAt);
    if (expiresAt <= new Date()) {
      throw new ValidationError("Session has expired");
    }

    return new UserDialer(this.http, session, undefined, undefined, this.auth);
  }

  /**
   * Simple SIWE authentication helper
   *
   * @remarks
   * Browser only - requires wallet provider.
   * Handles SIWE message creation and signing internally.
   *
   * @example
   * ```typescript
   * // With ethers.js signer
   * const userDialer = await dial.authenticateWithWallet({
   *   wallet: signer,
   *   chainId: 1
   * });
   * ```
   */
  async authenticateWithWallet(options: {
    wallet: {
      getAddress: () => Promise<string>;
      signMessage: (message: string) => Promise<string>;
    };
    chainId: number;
    domain?: string;
    uri?: string;
  }): Promise<UserDialer> {
    // Get address
    const address = await options.wallet.getAddress();

    // Get nonce (requires address)
    const nonce = await this.auth.getNonce(address);

    // Auto-detect domain from environment (fixes P2-7)
    const domain = options.domain ?? this.detectDomain();
    const uri = options.uri ?? this.detectUri();
    const issuedAt = new Date().toISOString();

    // Format SIWE message according to EIP-4361
    const message = [
      `${domain} wants you to sign in with your Ethereum account:`,
      address,
      "",
      "Sign in to Dial",
      "",
      `URI: ${uri}`,
      `Version: 1`,
      `Chain ID: ${options.chainId}`,
      `Nonce: ${nonce}`,
      `Issued At: ${issuedAt}`,
    ].join("\n");

    // Sign message
    const signature = await options.wallet.signMessage(message);

    // Authenticate
    return this.asUser({
      siwe: { message, signature },
    });
  }

  /**
   * Simple SIWS authentication helper for Solana
   *
   * @remarks
   * Browser only - requires Solana wallet adapter.
   *
   * @example
   * ```typescript
   * // With Solana wallet adapter
   * const userDialer = await dial.authenticateWithSolana({
   *   wallet: solanaWallet
   * });
   * ```
   */
  async authenticateWithSolana(options: {
    wallet: {
      publicKey: { toBase58: () => string };
      signMessage: (message: Uint8Array) => Promise<Uint8Array>;
    };
    domain?: string;
    uri?: string;
  }): Promise<UserDialer> {
    // Get address
    const address = options.wallet.publicKey.toBase58();

    // Get nonce (requires address)
    const nonce = await this.auth.getNonce(address);

    // Auto-detect domain from environment (fixes P2-7)
    const domain = options.domain ?? this.detectDomain();
    const uri = options.uri ?? this.detectUri();
    const issuedAt = new Date().toISOString();

    // Format SIWS message
    const message = [
      `${domain} wants you to sign in with your Solana account:`,
      address,
      "",
      "Sign in to Dial",
      "",
      `URI: ${uri}`,
      `Version: 1`,
      `Chain ID: mainnet`,
      `Nonce: ${nonce}`,
      `Issued At: ${issuedAt}`,
    ].join("\n");

    // Sign message
    const messageBytes = new TextEncoder().encode(message);
    const signatureBytes = await options.wallet.signMessage(messageBytes);

    // Encode signature as base58
    // Note: In a real implementation, use bs58 library
    const signature = this.uint8ArrayToBase58(signatureBytes);

    // Authenticate
    return this.asUser({
      siws: { message, signature },
    });
  }

  /**
   * Auto-detect the SIWE/SIWS domain from the current environment.
   * Returns the hostname for browsers, the extension origin for extensions,
   * or 'dial.wtf' as the fallback.
   * @internal
   */
  private detectDomain(): string {
    const env = detectEnvironment();

    if (env === 'extension') {
      // Chrome extension: use the full origin (chrome-extension://id)
      const chrome = (globalThis as Record<string, unknown>)['chrome'] as Record<string, unknown> | undefined;
      const runtime = chrome?.['runtime'] as Record<string, unknown> | undefined;
      const id = runtime?.['id'] as string | undefined;
      if (id) return `chrome-extension://${id}`;
    }

    if (env === 'browser') {
      const location = (globalThis as Record<string, unknown>)['location'] as { hostname?: string; origin?: string } | undefined;
      if (location?.hostname) return location.hostname;
    }

    return 'dial.wtf';
  }

  /**
   * Auto-detect the SIWE/SIWS URI from the current environment.
   * @internal
   */
  private detectUri(): string {
    const env = detectEnvironment();

    if (env === 'extension') {
      const chrome = (globalThis as Record<string, unknown>)['chrome'] as Record<string, unknown> | undefined;
      const runtime = chrome?.['runtime'] as Record<string, unknown> | undefined;
      const id = runtime?.['id'] as string | undefined;
      if (id) return `chrome-extension://${id}`;
    }

    if (env === 'browser') {
      const location = (globalThis as Record<string, unknown>)['location'] as { origin?: string } | undefined;
      if (location?.origin) return location.origin;
    }

    return 'https://dial.wtf';
  }

  /**
   * Simple base58 encoding for signatures
   * @internal
   */
  private uint8ArrayToBase58(bytes: Uint8Array): string {
    const ALPHABET =
      "123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz";
    let result = "";
    let num = BigInt(0);

    for (const byte of bytes) {
      num = num * BigInt(256) + BigInt(byte);
    }

    while (num > 0) {
      result = ALPHABET[Number(num % BigInt(58))] + result;
      num = num / BigInt(58);
    }

    // Add leading zeros
    for (const byte of bytes) {
      if (byte === 0) {
        result = "1" + result;
      } else {
        break;
      }
    }

    return result;
  }
}
