/**
 * @file voicemail.ts
 * @description Voicemail service.
 * @layer Services
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type {
  Voicemail,
  StartRecordingOptions,
  RecordingSession,
  GetVoicemailsOptions,
  VoicemailGreeting,
  SetGreetingOptions,
  VoicemailNotificationPreferences,
  Transcription,
  WaveformData,
} from '@dial-wtf/core';

export class VoicemailService extends BaseService {
  constructor(http: HttpClient) { super(http); }

  async startRecording(options: StartRecordingOptions): Promise<RecordingSession> { return this.http.post<RecordingSession>(this.endpoint('/voicemails/record'), options); }
  async stopRecording(voicemailId: string): Promise<Voicemail> { return this.http.post<Voicemail>(this.endpoint(`/voicemails/${voicemailId}/stop`)); }
  async record(options: StartRecordingOptions): Promise<RecordingSession> { return this.startRecording(options); }

  async getAll(options?: GetVoicemailsOptions): Promise<Voicemail[]> {
    return this.http.get<Voicemail[]>(this.endpoint('/voicemails'), { unreadOnly: options?.unreadOnly, limit: options?.limit, offset: options?.offset });
  }

  async get(voicemailId: string): Promise<Voicemail> { return this.http.get<Voicemail>(this.endpoint(`/voicemails/${voicemailId}`)); }
  async markAsRead(voicemailId: string): Promise<void> { await this.http.post(this.endpoint(`/voicemails/${voicemailId}/read`)); }
  async transcribe(voicemailId: string): Promise<Transcription> { return this.http.post<Transcription>(this.endpoint(`/voicemails/${voicemailId}/transcribe`)); }
  async delete(voicemailId: string): Promise<void> { await this.http.delete(this.endpoint(`/voicemails/${voicemailId}`)); }
  async archive(voicemailId: string): Promise<void> { await this.http.post(this.endpoint(`/voicemails/${voicemailId}/archive`)); }
  async getArchived(): Promise<Voicemail[]> { return this.http.get<Voicemail[]>(this.endpoint('/voicemails/archived')); }

  async download(voicemailId: string): Promise<Blob> {
    const voicemail = await this.get(voicemailId);
    const response = await fetch(voicemail.audioUrl);
    return response.blob();
  }

  async getWaveform(voicemailId: string): Promise<WaveformData> { return this.http.get<WaveformData>(this.endpoint(`/voicemails/${voicemailId}/waveform`)); }

  async setGreeting(options: SetGreetingOptions): Promise<VoicemailGreeting> {
    return this.http.post<VoicemailGreeting>(this.endpoint('/voicemails/greeting'), { text: options.text, voice: options.voice, duration: options.duration, hasAudioFile: !!options.audioFile });
  }

  async getGreeting(): Promise<VoicemailGreeting> { return this.http.get<VoicemailGreeting>(this.endpoint('/voicemails/greeting')); }
  async enable(): Promise<void> { await this.http.post(this.endpoint('/voicemails/settings'), { enabled: true }); }
  async disable(): Promise<void> { await this.http.post(this.endpoint('/voicemails/settings'), { enabled: false }); }
  async isEnabled(): Promise<boolean> { const r = await this.http.get<{ enabled: boolean }>(this.endpoint('/voicemails/settings')); return r.enabled; }
  async setNotificationPreferences(preferences: VoicemailNotificationPreferences): Promise<void> { await this.http.post(this.endpoint('/voicemails/notifications'), preferences); }
}
