/**
 * @file calls.ts
 * @description Calls service - Wallet-to-Wallet Calling.
 * @layer Services
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type {
  Call,
  StartCallOptions,
  DeclineCallOptions,
  CallRecording,
  WalletAddress,
  PaginationParams,
} from '@dial-wtf/core';

export class CallsService extends BaseService {
  private localStream?: MediaStream;
  private remoteStreams: Map<string, MediaStream> = new Map();

  constructor(http: HttpClient) {
    super(http);
  }

  async start(options: StartCallOptions): Promise<Call> {
    return this.http.post<Call>(this.endpoint('/calls'), options);
  }

  async answer(callId: string): Promise<Call> {
    return this.http.post<Call>(this.endpoint(`/calls/${callId}/answer`));
  }

  async decline(callId: string, options?: DeclineCallOptions): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/decline`), options);
  }

  async end(callId: string): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/end`));
  }

  async get(callId: string): Promise<Call> {
    return this.http.get<Call>(this.endpoint(`/calls/${callId}`));
  }

  async getHistory(params?: PaginationParams & { with?: WalletAddress }): Promise<Call[]> {
    const response = await this.http.get<Call[] | { calls: Call[]; pagination: unknown }>(
      this.endpoint('/calls'),
      params ? { ...params } : undefined
    );
    if (!Array.isArray(response) && 'calls' in response) {
      return response.calls;
    }
    return response as Call[];
  }

  async mute(callId: string): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/mute`));
    if (this.localStream) {
      this.localStream.getAudioTracks().forEach(track => { track.enabled = false; });
    }
  }

  async unmute(callId: string): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/unmute`));
    if (this.localStream) {
      this.localStream.getAudioTracks().forEach(track => { track.enabled = true; });
    }
  }

  async toggleMute(callId: string): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/toggle-mute`));
  }

  async disableVideo(callId: string): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/disable-video`));
    if (this.localStream) {
      this.localStream.getVideoTracks().forEach(track => { track.enabled = false; });
    }
  }

  async enableVideo(callId: string): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/enable-video`));
    if (this.localStream) {
      this.localStream.getVideoTracks().forEach(track => { track.enabled = true; });
    }
  }

  async toggleVideo(callId: string): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/toggle-video`));
  }

  async setSpeaker(callId: string, enabled: boolean): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/speaker`), { enabled });
  }

  getLocalStream(_callId: string): MediaStream | undefined {
    return this.localStream;
  }

  getRemoteStream(callId: string): MediaStream | undefined {
    return this.remoteStreams.get(callId);
  }

  async startRecording(callId: string): Promise<CallRecording> {
    return this.http.post<CallRecording>(this.endpoint(`/calls/${callId}/recording/start`));
  }

  async stopRecording(callId: string): Promise<CallRecording> {
    return this.http.post<CallRecording>(this.endpoint(`/calls/${callId}/recording/stop`));
  }

  setRingtone(audioUrl: string): void {
    if (typeof window !== 'undefined' && typeof Audio !== 'undefined') {
      const audio = new Audio(audioUrl);
      audio.preload = 'auto';
    }
  }

  /** @internal */
  _setLocalStream(stream: MediaStream): void { this.localStream = stream; }
  /** @internal */
  _setRemoteStream(callId: string, stream: MediaStream): void { this.remoteStreams.set(callId, stream); }
  /** @internal */
  _clearStreams(callId: string): void { this.remoteStreams.delete(callId); }
}
