/**
 * @file contacts-book.ts
 * @description ContactsBook — orchestrator for managing Dial contacts.
 * @layer Services
 *
 * Wraps an IContactsBookProvider with an event-driven API, in-memory cache,
 * and convenience helpers. Consumers subscribe to events for reactive updates.
 */

import EventEmitter3 from 'eventemitter3';
import type {
  IContactsBookProvider,
  ContactsBookConfig,
  ContactsBookEvents,
  Contact,
  AddContactOptions,
  UpdateContactOptions,
  WalletAddress,
} from '@dial-wtf/core';

export class ContactsBook {
  private readonly provider: IContactsBookProvider;
  private readonly emitter = new EventEmitter3();
  private cache: Map<string, Contact> = new Map();
  private loaded = false;

  constructor(provider: IContactsBookProvider, config?: ContactsBookConfig) {
    this.provider = provider;
    if (config?.autoLoad === true) {
      this.load().catch(() => {});
    }
  }

  async load(): Promise<Contact[]> {
    const contacts = await this.provider.getAll();
    this.cache.clear();
    for (const c of contacts) {
      this.cache.set(c.walletAddress.toLowerCase(), c);
    }
    this.loaded = true;
    this.emit('contacts:loaded', { contacts });
    return contacts;
  }

  async getAll(): Promise<Contact[]> {
    if (!this.loaded) await this.load();
    return Array.from(this.cache.values());
  }

  async get(walletAddress: WalletAddress): Promise<Contact | null> {
    if (!this.loaded) await this.load();
    return this.cache.get(walletAddress.toLowerCase()) ?? null;
  }

  async has(walletAddress: WalletAddress): Promise<boolean> {
    if (!this.loaded) await this.load();
    return this.cache.has(walletAddress.toLowerCase());
  }

  async add(options: AddContactOptions): Promise<Contact> {
    const contact = await this.provider.add(options);
    this.cache.set(contact.walletAddress.toLowerCase(), contact);
    this.emit('contact:added', { contact });
    return contact;
  }

  async update(options: UpdateContactOptions): Promise<Contact> {
    const contact = await this.provider.update(options);
    this.cache.set(contact.walletAddress.toLowerCase(), contact);
    this.emit('contact:updated', { contact });
    return contact;
  }

  async remove(walletAddress: WalletAddress): Promise<void> {
    await this.provider.remove(walletAddress);
    this.cache.delete(walletAddress.toLowerCase());
    this.emit('contact:removed', { walletAddress });
  }

  on<K extends keyof ContactsBookEvents>(event: K, callback: (payload: ContactsBookEvents[K]) => void): void {
    this.emitter.on(event, callback as (...args: unknown[]) => void);
  }

  off<K extends keyof ContactsBookEvents>(event: K, callback?: (payload: ContactsBookEvents[K]) => void): void {
    if (callback) {
      this.emitter.off(event, callback as (...args: unknown[]) => void);
    } else {
      this.emitter.removeAllListeners(event);
    }
  }

  removeAllListeners(): void {
    this.emitter.removeAllListeners();
  }

  private emit<K extends keyof ContactsBookEvents>(event: K, payload: ContactsBookEvents[K]): void {
    this.emitter.emit(event, payload);
  }
}
