/**
 * @file chats.ts
 * @description Chat service - E2EE DMs and Groups.
 * @layer Services
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type {
  Message,
  SendMessageOptions,
  Conversation,
  GetConversationOptions,
  GetMessagesOptions,
  CreateThreadOptions,
  Thread,
  Group,
  CreateGroupOptions,
  WalletAddress,
  PaginationParams,
} from '@dial-wtf/core';

export class ChatService extends BaseService {
  constructor(http: HttpClient) {
    super(http);
  }

  async send(options: SendMessageOptions): Promise<Message> {
    if (options.media?.file) {
      return this.sendWithMedia(options);
    }

    return this.http.post<Message>(this.endpoint('/chat/messages'), {
      to: options.to,
      content: options.content,
      type: options.type ?? 'text',
      threadId: options.threadId,
      provider: options.provider,
      encrypted: options.encrypted,
      replyTo: options.replyTo,
      mentions: options.mentions,
    });
  }

  private async sendWithMedia(options: SendMessageOptions): Promise<Message> {
    return this.http.post<Message>(this.endpoint('/chat/messages'), {
      to: options.to,
      content: options.media?.caption ?? options.content,
      type: options.type,
      threadId: options.threadId,
      provider: options.provider,
      encrypted: options.encrypted,
      replyTo: options.replyTo,
      mentions: options.mentions,
      hasMedia: true,
      mediaDuration: options.media?.duration,
    });
  }

  async listThreads(params?: PaginationParams): Promise<Conversation[]> {
    return this.http.get<Conversation[]>(this.endpoint('/chat/threads'), params ? { ...params } : undefined);
  }

  /** @deprecated Use listThreads() */
  async getConversations(params?: PaginationParams): Promise<Conversation[]> {
    return this.listThreads(params);
  }

  async getThread(options: GetConversationOptions): Promise<Conversation> {
    return this.http.get<Conversation>(this.endpoint('/chat/threads'), {
      with: options.with,
      threadModel: options.threadModel,
      provider: options.provider,
    });
  }

  /** @deprecated Use getThread() */
  async getConversation(options: GetConversationOptions): Promise<Conversation> {
    return this.getThread(options);
  }

  async listMessages(options: GetMessagesOptions): Promise<Message[]> {
    return this.http.get<Message[]>(this.endpoint('/chat/messages'), {
      with: options.with,
      threadId: options.threadId,
      before: options.before?.toString(),
      after: options.after?.toString(),
      limit: options.limit,
      offset: options.offset,
    });
  }

  /** @deprecated Use listMessages() */
  async getMessages(options: GetMessagesOptions): Promise<Message[]> {
    return this.listMessages(options);
  }

  async markAsRead(messageId: string): Promise<void> {
    await this.http.post(this.endpoint(`/chat/messages/${messageId}/read`));
  }

  async addReaction(options: { messageId: string; emoji: string }): Promise<void> {
    await this.http.post(this.endpoint(`/chat/messages/${options.messageId}/reactions`), { emoji: options.emoji });
  }

  async removeReaction(options: { messageId: string; emoji: string }): Promise<void> {
    await this.http.delete(this.endpoint(`/chat/messages/${options.messageId}/reactions/${encodeURIComponent(options.emoji)}`));
  }

  async startTyping(options: { threadId: string }): Promise<void> {
    await this.http.post(this.endpoint('/chat/typing'), { threadId: options.threadId, isTyping: true });
  }

  async stopTyping(options: { threadId: string }): Promise<void> {
    await this.http.post(this.endpoint('/chat/typing'), { threadId: options.threadId, isTyping: false });
  }

  async createDM(options: { otherDialUserId: WalletAddress }): Promise<Thread> {
    return this.http.post<Thread>(this.endpoint('/chat/threads'), { type: 'dm', participants: [options.otherDialUserId] });
  }

  /** @deprecated Use createDM() or createGroup() */
  async createThread(options: CreateThreadOptions): Promise<Thread> {
    return this.http.post<Thread>(this.endpoint('/chat/threads'), options);
  }

  async createManagedThread(options: { participants: WalletAddress[]; topic: string; metadata?: Record<string, unknown> }): Promise<Thread> {
    return this.http.post<Thread>(this.endpoint('/chat/threads/managed'), options);
  }

  async listManagedThreads(options?: { filters?: Record<string, unknown> } & PaginationParams): Promise<Thread[]> {
    return this.http.get<Thread[]>(this.endpoint('/chat/threads/managed'), options?.filters as Record<string, string | number | boolean>);
  }

  async archiveThread(threadId: string): Promise<void> {
    await this.http.post(this.endpoint(`/chat/threads/${threadId}/archive`));
  }

  async createGroup(options: CreateGroupOptions): Promise<Group> {
    return this.http.post<Group>(this.endpoint('/chat/threads'), {
      type: 'group',
      name: options.name,
      participants: options.participants,
      provider: options.provider,
    });
  }

  async inviteToGroup(options: { groupId: string; addresses: WalletAddress[] }): Promise<void> {
    await this.http.post(this.endpoint(`/chat/threads/${options.groupId}/invite`), { addresses: options.addresses });
  }

  async addMember(options: { threadId: string; address: WalletAddress }): Promise<void> {
    await this.http.post(this.endpoint(`/chat/threads/${options.threadId}/members`), { address: options.address });
  }

  /** @deprecated Use addMember() */
  async addGroupMember(options: { groupId: string; address: WalletAddress }): Promise<void> {
    return this.addMember({ threadId: options.groupId, address: options.address });
  }

  async removeMember(options: { threadId: string; address: WalletAddress }): Promise<void> {
    await this.http.delete(this.endpoint(`/chat/threads/${options.threadId}/members/${options.address}`));
  }

  /** @deprecated Use removeMember() */
  async removeGroupMember(options: { groupId: string; address: WalletAddress }): Promise<void> {
    return this.removeMember({ threadId: options.groupId, address: options.address });
  }

  async leaveGroup(threadId: string): Promise<void> {
    await this.http.post(this.endpoint(`/chat/threads/${threadId}/leave`));
  }

  async updateGroup(options: { threadId: string; name?: string; avatar?: File | Blob }): Promise<Group> {
    return this.http.patch<Group>(this.endpoint(`/chat/threads/${options.threadId}`), { name: options.name });
  }

  async delete(messageId: string, options?: { forEveryone?: boolean }): Promise<void> {
    await this.http.delete(this.endpoint(`/chat/messages/${messageId}`), {
      headers: options?.forEveryone ? { 'X-Delete-For-Everyone': 'true' } : undefined,
    });
  }

  async search(options: { query: string; threadId?: string; limit?: number }): Promise<Message[]> {
    return this.http.get<Message[]>(this.endpoint('/chat/messages/search'), options);
  }
}
