/**
 * @file profile.ts
 * @description Profile service - Dial Profile Management.
 * @layer Services
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type {
  DialProfile,
  UpdateProfileOptions,
  ProfileStatus,
  StatusInfo,
  SetStatusOptions,
  Contact,
  AddContactOptions,
  UpdateContactOptions,
  ProfilePreferences,
  PrivacySettings,
  NotificationSettings,
  DoNotDisturbOptions,
  WalletAddress,
  PaginationParams,
} from '@dial-wtf/core';

export class ProfileService extends BaseService {
  constructor(http: HttpClient) {
    super(http);
  }

  async get(): Promise<DialProfile> {
    return this.http.get<DialProfile>(this.endpoint('/profile'));
  }

  async getProfile(options: { walletAddress: WalletAddress }): Promise<DialProfile> {
    return this.http.get<DialProfile>(this.endpoint(`/profiles/${options.walletAddress}`));
  }

  async update(options: UpdateProfileOptions): Promise<DialProfile> {
    return this.http.patch<DialProfile>(this.endpoint('/profile'), options);
  }

  async updateAvatar(_options: { file: File | Blob }): Promise<DialProfile> {
    return this.http.post<DialProfile>(this.endpoint('/profile/avatar'), { hasAvatar: true });
  }

  async setStatus(status: ProfileStatus, options?: SetStatusOptions): Promise<void> {
    await this.http.post(this.endpoint('/profile/status'), { status, customMessage: options?.customMessage });
  }

  async getStatus(): Promise<StatusInfo> {
    return this.http.get<StatusInfo>(this.endpoint('/profile/status'));
  }

  async updatePreferences(preferences: Partial<ProfilePreferences>): Promise<void> {
    await this.http.patch(this.endpoint('/profile/preferences'), preferences);
  }

  async updatePrivacy(privacy: Partial<PrivacySettings>): Promise<void> {
    await this.http.patch(this.endpoint('/profile/privacy'), privacy);
  }

  async updateNotificationSettings(settings: Partial<NotificationSettings>): Promise<void> {
    await this.http.patch(this.endpoint('/profile/notifications'), settings);
  }

  async enableDoNotDisturb(options?: DoNotDisturbOptions): Promise<void> {
    await this.http.post(this.endpoint('/profile/dnd'), { enabled: true, ...options });
  }

  async disableDoNotDisturb(): Promise<void> {
    await this.http.post(this.endpoint('/profile/dnd'), { enabled: false });
  }

  async blockUser(walletAddress: WalletAddress): Promise<void> {
    await this.http.post(this.endpoint('/profile/blocked'), { walletAddress });
  }

  async unblockUser(walletAddress: WalletAddress): Promise<void> {
    await this.http.delete(this.endpoint(`/profile/blocked/${walletAddress}`));
  }

  async getBlockedUsers(): Promise<WalletAddress[]> {
    return this.http.get<WalletAddress[]>(this.endpoint('/profile/blocked'));
  }

  async linkENS(options: { ensName: string }): Promise<void> {
    await this.http.post(this.endpoint('/profile/verify/ens'), options);
  }

  async verifyTwitter(options: { handle: string }): Promise<void> {
    await this.http.post(this.endpoint('/profile/verify/twitter'), options);
  }

  async verifyGithub(options: { username: string }): Promise<void> {
    await this.http.post(this.endpoint('/profile/verify/github'), options);
  }

  /**
   * @deprecated Use `userDialer.contacts.add()` instead. ProfileService contact
   * methods bypass ContactsBook's cache and event system, causing stale reads.
   */
  async addContact(options: AddContactOptions): Promise<Contact> {
    return this.http.post<Contact>(this.endpoint('/profile/contacts'), options);
  }

  /**
   * @deprecated Use `userDialer.contacts.getAll()` instead. ProfileService contact
   * methods bypass ContactsBook's cache and event system, causing stale reads.
   */
  async getContacts(params?: PaginationParams): Promise<Contact[]> {
    return this.http.get<Contact[]>(this.endpoint('/profile/contacts'), params ? { ...params } : undefined);
  }

  /**
   * @deprecated Use `userDialer.contacts.update()` instead. ProfileService contact
   * methods bypass ContactsBook's cache and event system, causing stale reads.
   */
  async updateContact(options: UpdateContactOptions): Promise<Contact> {
    return this.http.patch<Contact>(this.endpoint(`/profile/contacts/${options.walletAddress}`), options);
  }

  /**
   * @deprecated Use `userDialer.contacts.remove()` instead. ProfileService contact
   * methods bypass ContactsBook's cache and event system, causing stale reads.
   */
  async removeContact(walletAddress: WalletAddress): Promise<void> {
    await this.http.delete(this.endpoint(`/profile/contacts/${walletAddress}`));
  }
}
