/**
 * @file client.ts
 * @description HTTP client for Dial API with AbortSignal composition.
 * @layer HTTP
 *
 * Addresses audit finding C4: composes caller signal with internal timeout signal
 * using AbortSignal.any() where available, with a polyfill fallback.
 */

import type {
  ResolvedClientConfig,
  RequestOptions,
  ApiResponse,
} from '@dial-wtf/core';
import {
  ApiError,
  NetworkError,
  TimeoutError,
  RateLimitError,
  AuthError,
  NotFoundError,
  PermissionDeniedError,
} from '@dial-wtf/core';
import type { IHttpTransport } from '@dial-wtf/core';

/** Callback to refresh a session and return a new auth token. */
export type SessionRefresher = () => Promise<string>;

/** HTTP client implementing IHttpTransport */
export class HttpClient implements IHttpTransport {
  private readonly config: ResolvedClientConfig;
  private authToken?: string;
  private sessionRefresher?: SessionRefresher;
  private refreshPromise?: Promise<string>;
  private readonly inflightGets = new Map<string, Promise<unknown>>();

  constructor(config: ResolvedClientConfig) {
    this.config = config;
  }

  setAuthToken(token: string | undefined): void {
    this.authToken = token;
  }

  getAuthToken(): string | undefined {
    return this.authToken;
  }

  /**
   * Register a callback to refresh the session on 401 (P2-5 fix).
   * The callback should refresh the session and return the new auth token.
   */
  setSessionRefresher(refresher: SessionRefresher | undefined): void {
    this.sessionRefresher = refresher;
  }

  private buildUrl(endpoint: string, params?: Record<string, string | number | boolean | undefined>): string {
    const base = this.config.baseUrl.replace(/\/+$/, '');
    const path = endpoint.startsWith('/') ? endpoint : `/${endpoint}`;
    const url = new URL(`${base}${path}`);

    if (params) {
      Object.entries(params).forEach(([key, value]) => {
        if (value !== undefined) {
          url.searchParams.set(key, String(value));
        }
      });
    }

    return url.toString();
  }

  private buildHeaders(customHeaders?: Record<string, string>): Record<string, string> {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      'User-Agent': `@dial-wtf/client`,
    };

    if (this.config.apiKey) {
      headers['x-api-key'] = this.config.apiKey;
    }

    if (this.authToken) {
      headers['Authorization'] = `Bearer ${this.authToken}`;
    }

    if (customHeaders) {
      Object.assign(headers, customHeaders);
    }

    return headers;
  }

  /**
   * Compose multiple AbortSignals into one.
   * Uses AbortSignal.any() where available (Node 20+, modern browsers),
   * falls back to manual composition.
   */
  private composeSignals(signals: AbortSignal[]): { signal: AbortSignal; cleanup: () => void } {
    const filtered = signals.filter(Boolean);
    if (filtered.length === 0) {
      const controller = new AbortController();
      return { signal: controller.signal, cleanup: () => {} };
    }
    if (filtered.length === 1) {
      return { signal: filtered[0]!, cleanup: () => {} };
    }

    // Use AbortSignal.any() if available (fixes C4)
    if ('any' in AbortSignal) {
      return {
        signal: (AbortSignal as unknown as { any: (signals: AbortSignal[]) => AbortSignal }).any(filtered),
        cleanup: () => {},
      };
    }

    // Polyfill: create a composite controller
    const controller = new AbortController();
    const onAbort = () => controller.abort();
    for (const sig of filtered) {
      if (sig.aborted) {
        controller.abort();
        return { signal: controller.signal, cleanup: () => {} };
      }
      sig.addEventListener('abort', onAbort, { once: true });
    }
    const cleanup = () => {
      for (const sig of filtered) {
        sig.removeEventListener('abort', onAbort);
      }
    };
    return { signal: controller.signal, cleanup };
  }

  async request<T>(
    endpoint: string,
    options: RequestOptions = {},
    _isRetry = false,
  ): Promise<T> {
    const { method = 'GET', headers, body, timeout, signal } = options;
    const url = this.buildUrl(endpoint);
    const requestHeaders = this.buildHeaders(headers);

    // Create timeout controller
    const timeoutController = new AbortController();
    const timeoutMs = timeout ?? this.config.timeout;
    const timeoutId = setTimeout(() => timeoutController.abort(), timeoutMs);

    // Compose caller signal + timeout signal (fixes C4)
    const signals: AbortSignal[] = [timeoutController.signal];
    if (signal) signals.push(signal);
    const { signal: composedSignal, cleanup } = this.composeSignals(signals);

    try {
      if (this.config.debug) {
        console.log(`[Dial SDK] ${method} ${url}`);
      }

      const response = await this.config.fetch(url, {
        method,
        headers: requestHeaders,
        body: body ? JSON.stringify(body) : undefined,
        signal: composedSignal,
      });

      clearTimeout(timeoutId);
      cleanup();

      const contentType = response.headers.get('content-type');
      let data: unknown;

      if (contentType?.includes('application/json')) {
        data = await response.json();
      } else {
        data = await response.text();
      }

      if (!response.ok) {
        // Auto-refresh on 401 and retry once (P2-5 fix)
        if (response.status === 401 && !_isRetry && this.sessionRefresher) {
          const newToken = await this.refreshSession();
          this.setAuthToken(newToken);
          return this.request<T>(endpoint, options, true);
        }
        this.handleErrorResponse(response.status, data, response.headers);
      }

      if (typeof data === 'object' && data !== null && 'data' in data) {
        return (data as ApiResponse<T>).data;
      }

      return data as T;
    } catch (error) {
      clearTimeout(timeoutId);
      cleanup();

      if (error instanceof Error) {
        if (error.name === 'AbortError') {
          throw new TimeoutError();
        }
        // Auto-refresh on AuthError and retry once (P2-5 fix)
        if (error instanceof AuthError && !_isRetry && this.sessionRefresher) {
          const newToken = await this.refreshSession();
          this.setAuthToken(newToken);
          return this.request<T>(endpoint, options, true);
        }
        if (
          error instanceof ApiError ||
          error instanceof AuthError ||
          error instanceof NotFoundError ||
          error instanceof RateLimitError ||
          error instanceof PermissionDeniedError
        ) {
          throw error;
        }
        throw new NetworkError(error.message);
      }

      throw new NetworkError('Unknown network error');
    }
  }

  /**
   * Refresh session, deduplicating concurrent refresh calls.
   * @internal
   */
  private async refreshSession(): Promise<string> {
    if (!this.refreshPromise) {
      this.refreshPromise = this.sessionRefresher!().finally(() => {
        this.refreshPromise = undefined;
      });
    }
    return this.refreshPromise;
  }

  private handleErrorResponse(
    status: number,
    body: unknown,
    headers: Headers
  ): never {
    switch (status) {
      case 401:
        throw new AuthError(this.getErrorMessage(body, 'Unauthorized'));
      case 403:
        throw new PermissionDeniedError(this.getErrorMessage(body, 'Permission denied'));
      case 404:
        throw new NotFoundError(this.getErrorMessage(body, 'Endpoint not found'));
      case 429: {
        const retryAfter = headers.get('retry-after');
        throw new RateLimitError(
          this.getErrorMessage(body, 'Rate limit exceeded'),
          retryAfter ? parseInt(retryAfter, 10) : undefined
        );
      }
      default:
        throw ApiError.fromResponse(status, body);
    }
  }

  private getErrorMessage(body: unknown, fallback: string): string {
    if (typeof body === 'object' && body !== null) {
      const errorBody = body as Record<string, unknown>;
      if (typeof errorBody['error'] === 'string') {
        return errorBody['error'];
      }
      if (typeof errorBody['message'] === 'string') {
        return errorBody['message'];
      }
    }
    return fallback;
  }

  async get<T>(
    endpoint: string,
    params?: Record<string, unknown>,
    options?: Omit<RequestOptions, 'method' | 'body'>
  ): Promise<T> {
    // Build the cache key for deduplication (P2-6 fix)
    const cacheKey = params
      ? this.buildUrl(endpoint, this.toUrlParams(params))
      : endpoint;

    // Return existing in-flight promise if one exists
    const inflight = this.inflightGets.get(cacheKey);
    if (inflight) return inflight as Promise<T>;

    const promise = this.executeGet<T>(endpoint, params, options);

    // Store in-flight and clean up when done
    this.inflightGets.set(cacheKey, promise);
    promise.finally(() => this.inflightGets.delete(cacheKey));

    return promise;
  }

  private async executeGet<T>(
    endpoint: string,
    params?: Record<string, unknown>,
    options?: Omit<RequestOptions, 'method' | 'body'>
  ): Promise<T> {
    if (params) {
      const urlParams = this.toUrlParams(params);
      const url = this.buildUrl(endpoint, urlParams);
      return this.request<T>(url.replace(this.config.baseUrl, ''), {
        ...options,
        method: 'GET',
      });
    }
    return this.request<T>(endpoint, {
      ...options,
      method: 'GET',
    });
  }

  private toUrlParams(params: Record<string, unknown>): Record<string, string | number | boolean | undefined> {
    const urlParams: Record<string, string | number | boolean | undefined> = {};
    for (const [key, value] of Object.entries(params)) {
      if (value !== undefined && value !== null) {
        if (value instanceof Date) {
          urlParams[key] = value.toISOString();
        } else if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
          urlParams[key] = value;
        } else {
          urlParams[key] = String(value);
        }
      }
    }
    return urlParams;
  }

  async post<T>(
    endpoint: string,
    body?: unknown,
    options?: Omit<RequestOptions, 'method'>
  ): Promise<T> {
    return this.request<T>(endpoint, {
      ...options,
      method: 'POST',
      body,
    });
  }

  async put<T>(
    endpoint: string,
    body?: unknown,
    options?: Omit<RequestOptions, 'method'>
  ): Promise<T> {
    return this.request<T>(endpoint, {
      ...options,
      method: 'PUT',
      body,
    });
  }

  async patch<T>(
    endpoint: string,
    body?: unknown,
    options?: Omit<RequestOptions, 'method'>
  ): Promise<T> {
    return this.request<T>(endpoint, {
      ...options,
      method: 'PATCH',
      body,
    });
  }

  async delete<T>(
    endpoint: string,
    options?: Omit<RequestOptions, 'method' | 'body'>
  ): Promise<T> {
    return this.request<T>(endpoint, {
      ...options,
      method: 'DELETE',
    });
  }
}
